<template>
  <scroll :data="data"
          ref="listview"
          :listenerScroll="listenerScroll"
          :probeType="probeType"
          @scroll="scroll">
    <div class="wrap" style="overflow: hidden">
      <ul v-for="group in data" class="list" ref="listgroup">
        <li class="list-title">{{group.title}}</li>
        <ul v-for="item in group.item" class="list-item">
          <li @click="listitemClick(item)">
              <img v-lazy="item.singer_pic" :onerror="errorUserPhoto" alt="" class="singer-pic">
              <span class="singer-name">{{item.singer_name}}</span>
          </li>
        </ul>
      </ul>
    </div>
    <div class="shortcut-list" ref="shortcut" @touchstart="onShortCut()" @touchmove.stop.prevent="onShortCutMove">
      <ul>
        <li v-for="(title,index) in shortcutList" :data-index="index" :class="{'active':currentIndex == index}">{{title}}</li>
      </ul>
    </div>
    <div class="list-fixed" v-show="fixedTitle" ref="listfixed">
      <h2>{{fixedTitle}}</h2>
    </div>
  </scroll>
</template>

<script>
import Scroll from "../scroll/scroll"
import userphoto from "../../assets/image/singerPic.png"
const LI_LENGTH = 16;
const TITLE_LENGTH = 25;
export default {
  name: "listview",
  data(){
    return {
      errorUserPhoto:'this.src="'+userphoto+'"',
      listHeight: [],
      currentIndex: 0,
      scrollY: -1,
      diff: -1
    }
  },
  props: {
    data: {
      type: Array,
      default: []
    }
  },
  created(){
    this.touch = {};
    this.probeType = 3;
    this.listenerScroll = true;
  },
  computed:{
    shortcutList(){
      var num = 0;
      this.data.forEach((item,index) => {
        num ++;
      });
      var height = num * 16;
      var timer = setInterval(() => {
        if (this.$refs.shortcut){
          this.$refs.shortcut.style.marginTop = -height/2 + 'px';
          clearInterval(timer);
        }
      },20);
      return this.data.map((group) =>{
        return group.title.substring(0,1);
      });
    },
    fixedTitle(){
      if (this.scrollY > 0){
        return '';
      }
      return this.data[this.currentIndex] ? this.data[this.currentIndex].title : '';
    }
  },
  methods:{
    onShortCut(e){
      e = e || window.event;
      this.touch.firstIndex = e.target.getAttribute('data-index');
      this.currentIndex = this.touch.firstIndex;
      this.touch.y1 = e.changedTouches[0].pageY;
      this.$refs.listview.scroll.scrollToElement(this.$refs.listgroup[this.touch.firstIndex],0);
    },
    onShortCutMove(e){
      e = e || window.event;
      var changeIndex;
      this.touch.y2 = e.changedTouches[0].pageY;
      var changeTouch = this.touch.y2 - this.touch.y1;
      changeIndex = Math.floor(changeTouch/LI_LENGTH);
      var lastIndex = changeIndex + parseInt(this.touch.firstIndex);
      this.currentIndex = lastIndex;
      this.$refs.listview.scroll.scrollToElement(this.$refs.listgroup[lastIndex],0);
    },
    _calculateHeight(){
      this.listHeight = [];
      const list = this.$refs.listgroup;
      let height = 0;
      this.listHeight.push(height);
      for(var i=0;i<list.length;i++){
        height += list[i].clientHeight;
        this.listHeight.push(height);
      }
    },
    scroll(pos){
      this.scrollY = pos.y;
    },
    listitemClick(item){
      this.$emit('singerChildren',item);
    }
  },
  watch: {
    data:{
      handler: function () {
        this.$nextTick(() =>{
          this._calculateHeight()
        })
      },
      immediate:true,
      deep:true
    },
    scrollY(){
      const list = this.listHeight;
      let y =  this.scrollY;
      if (y > 0){
        this.currentIndex = 0;
        return;
      }
      for (let i = 0;i<list.length;i++){
        if (!list[i+1] || (-y >= list[i]) && -y < list[i+1]){
          this.currentIndex = i;
          this.diff = y + list[i+1];
          return;
        }
      }
    },
    diff(newVal){
      let fixedTop = (newVal > 0 && newVal < TITLE_LENGTH) ? newVal - TITLE_LENGTH: 0;
      if (this.fixedTop == fixedTop) {
        return;
      }
      this.fixedTop = fixedTop;
      this.$refs.listfixed.style.marginTop = fixedTop + 'px';
    }
  },
  components:{
    Scroll
  }
}
</script>

<style scoped>
  .list{
    color: hsla(0,0%,100%,.5);
    padding-bottom: 20px;
  }
  .list .list-title{
    padding-left: 20px;
    text-align: left;
    background-color: #333;
    font-size:12px;
    line-height: 25px;
  }
  .list .list-item li{
    display: flex;
    justify-content: flex-start;
    align-items: center;
    padding: 25px 0 0 25px;
  }
  .list .list-item li{
    font-size: 14px;
  }
  .list .list-item li .singer-pic{
    width: 50px;
    height: 50px;
    -webkit-border-radius: 50%;
    -moz-border-radius: 50%;
    border-radius: 50%;
    margin-right: 20px;
  }
  .shortcut-list{
    position:absolute;
    width:25px;
    right:0;
    top: 50%;
    z-index: 10;
    color: #fff;
  }
  .shortcut-list ul li{
    text-align: center;
    line-height: 16px;
    font-size: 12px;
  }
  .shortcut-list ul li.active{
    color:#ffcd32;
  }
  .list-fixed{
    position: absolute;
    width: 100%;
    left: 0;
    top: 0;
  }
  .list-fixed h2{
    width: 100%;
    padding-left: 20px;
    text-align: left;
    background-color: #333;
    font-size:12px;
    line-height: 25px;
    color: hsla(0,0%,100%,.5);
  }
</style>



