import axios from "axios";

export function getLyric(songmid){
  const url = '/api/getLyric';
  const data = {
    pcachetime:Date.now(),
    songmid:songmid,
    g_tk:714314754,
    loginUin:1358302452,
    hostUin:0,
    format:'json',
    inCharset:'utf8',
    outCharset:'utf-8',
    notice:0,
    platform:'yqq',
    needNewCode:0
  };
  return axios.get(url,{
    params:data
  }).then((res) => {
    return Promise.resolve(res.data);
  }).catch((err) => {
    console.log(err)
  })
}



