<template>
  <div class="progress-bar" ref="progressBar" @click="progrssClick">
    <div class="progress" ref="progress"></div>
    <div class="progress-btn" ref="progressBtn"
         @touchstart.prevent="progressBtnTouchStart"
         @touchmove.prevent="progressBtnTouchMove"
         @touchend="progressBtnTouchEnd">
    </div>
  </div>
</template>

<script>
const BTN_WIDTH = 16;
export default {
  name: "progress-bar",
  props:{
    percent:{
      type:Number,
      default:0
    }
  },
  created(){
    this.touch = {};
    this.progressBarWidth = 0;
    this.firstLoad = false;
  },
  methods:{
    progressBtnTouchStart(e){
      this.touch.init = true;
      this.touch.moveFlag = false;
      this.touch.touchLeft = this.$refs.progress.clientWidth;
      this.touch.touchInit = e.changedTouches[0].pageX;
    },
    progressBtnTouchMove(e){
      if (!this.touch.init){
        return;
      }
      this.touch.moveFlag = true;
      let touch = e.changedTouches[0].pageX;
      let changeTouch = touch - this.touch.touchInit;
      this.touch.endTouch = changeTouch + this.touch.touchLeft;
      const progressBarWidth = this.$refs.progressBar.clientWidth;
      this.touch.endTouch = Math.max(this.touch.endTouch,0);
      if (this.touch.endTouch > 0){
        this.touch.endTouch = Math.min(this.touch.endTouch,progressBarWidth);
      }
      this.$refs.progress.style.width =  this.touch.endTouch + 'px';
      this.$refs.progress.style.width = this.touch.endTouch + 'px';
      this.$refs.progressBtn.style.left = this.touch.endTouch + 'px';
      if (this.touch.endTouch >= progressBarWidth - BTN_WIDTH){
        this.$refs.progressBtn.style.left = progressBarWidth - BTN_WIDTH + 'px';
      }
    },
    progressBtnTouchEnd(){
      this.touch.init = false;
      if (!this.touch.moveFlag) {
        this.touch.moveFlag = false;
        return;
      }
      const progressBarWidth = this.$refs.progressBar.clientWidth;
      let percent = this.touch.endTouch/progressBarWidth;
      this.$emit('changePercent',percent);
      this.touch.moveFlag = false;
    },
    progrssClick(e){
      let boundWidth = this.$refs.progressBar.getBoundingClientRect().left;
      let width = e.pageX - boundWidth;
      const progressBarWidth = this.$refs.progressBar.clientWidth;
      this.$refs.progress.style.width =  width + 'px';
      this.$refs.progressBtn.style.left = width + 'px';
      if (width >= progressBarWidth - BTN_WIDTH){
        this.$refs.progressBtn.style.left = progressBarWidth - BTN_WIDTH + 'px';
      }
      let percent = width/progressBarWidth;
      this.$emit('changePercent',percent);
    },
  },
  watch:{
    percent(){
      if (this.touch.init){
        return;
      }
      if (!this.firstLoad){
        this.progressBarWidth = this.$refs.progressBar.clientWidth;
        this.firstLoad = !this.firstLoad;
      }
      const progressBarWidth = this.progressBarWidth;
      this.$refs.progress.style.width = this.percent * progressBarWidth + 'px';
      if (this.percent * progressBarWidth >= progressBarWidth - BTN_WIDTH){
        this.$refs.progressBtn.style.left = progressBarWidth - BTN_WIDTH + 'px';
        return;
      }
      this.$refs.progressBtn.style.left = this.percent * progressBarWidth + 'px';
    }
  }
}
</script>

<style scoped>
  .progress-bar{
    position: relative;
    width: 100%;
    height: 4px;
    background: rgba(0,0,0,.3);
  }
  .progress-bar .progress{
    width: 0;
    height: 100%;
    background-color:#ffcd32;
  }
  .progress-bar .progress-btn{
    position: absolute;
    left: 0;
    top: -6px;
    width: 10px;
    height: 10px;
    border-radius: 50%;
    border: 3px solid #ffffff;
    background-color:#ffcd32;
  }
</style>



