<template>
  <div ref="wrapper" class="wrapper">
    <slot></slot>
  </div>
</template>

<script>
  import BScroll from 'better-scroll'
  export default {
    name: "scroll",
    props: {
      probeType: {
        type: Number,
        default: 1
      },
      click: {
        type: Boolean,
        default: true
      },
      data: {
        type: Array,
        default :null
      },
      listenerScroll: {
        type: Boolean,
        default: false
      },
      ifSetHeight: {
        type: Boolean,
        default: true
      },
      height: {
        type:Number,
        default:0
      }
    },
    mounted:function(){
      this.$nextTick(() => {
        if (this.ifSetHeight) {
          this._setHeight();
        }else{
          this.$refs.wrapper.style.height = this.height + 'px'
        }
        this._initScroll();
      });
    },
    methods: {
      _initScroll(){
        if (!this.$refs.wrapper){
          return
        }
        this.scroll = new BScroll(this.$refs.wrapper,{
          probeType:this.probeType,
          click:this.click
        })
        if (this.listenerScroll){
          let me = this;
          this.scroll.on('scroll',(pos) => {
            me.$emit('scroll',pos,this,this.scroll);
          })
        }
      },
      _setHeight(){
        if (!this.$refs.wrapper){
          return
        }
        let height = document.documentElement.clientHeight;
        let obj = this.$refs.wrapper;
        let distance = 0;
        while (obj != document.body){
          if (obj == null){
            break;
          }
          distance += obj.offsetTop;
          obj = obj.offsetParent;
        }
        this.$refs.wrapper.style.height = height - distance + "px";
      }
    },
    watch: {
        data(){
          this.$nextTick(()=>{
            if (this.ifSetHeight) {
              this._setHeight();
            }else{
              this.$refs.wrapper.style.height = this.height + 'px'
            }
            this.scroll.refresh();
          })
        }
    }
  }
</script>
<style scoped>
  .wrapper{
    position: relative;
  }
</style>



