<template>
  <div class="music-list">
    <div class="head">
      <div class="back">
        <i class="iconfont icon-houtui" @click="goBack"></i>
      </div>
      <h1 class="title">{{title}}</h1>
    </div>
    <div class="bg-img" :style="bgStyle" ref="bgImg">
      <div class="filter">
        <div class="play-wrapper" ref="play" @click="random" v-show="songs.length">
          <i class="iconfont icon-bofang"></i>
          <span>随机播放全部</span>
        </div>
      </div>
    </div>
    <div class="bg-layer" ref="bgLayer"></div>
    <div class="songs-list">
      <songs-list :songs="songs" @scrollY="scrollY" @scrollobj="scrollobj" @select="selectItem"></songs-list>
    </div>
  </div>
</template>

<script>
import SongsList from '../../base/songslist/songslist'
import {mapActions} from 'vuex'
const MIN_TOP = 50;
export default {
  name: "music-list",
  props:{
    songs:{
      type: Array,
      default: []
    },
    title:{
      type:String,
      default:''
    },
    bgImg:{
      type:String,
      default:''
    }
  },
  data(){
    return{
      flag: false,
    }
  },
  methods:{
    goBack(){
      this.$router.push('/singer');
    },
    scrollobj(vm,scroll){
      this.vm = vm;
      this.scroll = scroll;
    },
    scrollY(newY){
      let zIndex = 0;
      let scale = 1;
      let bgTop = this.initTop + newY;
      this.$refs.bgLayer.style.top = Math.max(bgTop,MIN_TOP) + 'px';
      const percent = Math.abs(newY / this.initTop);
      if (newY > 0){
        this.$refs.bgImg.style.transform = `scale(${1 + percent})`;
        zIndex = 10;
      }
      if (newY < -this.initTop +  MIN_TOP){
        zIndex = 10;
        this.$refs.bgImg.style.paddingTop =  MIN_TOP + 'px';
        this.$refs.play.style.display = 'none';
        this.flag = true;
      }else{
        this.$refs.bgImg.style.paddingTop =  '70%';
        this.$refs.play.style.display = 'block';
        zIndex = 0;
        this.flag = false;
      }
      this.$refs.bgImg.style.zIndex = zIndex;
    },
    selectItem(item,index){
      this.selectPlay({
        list: this.songs,
        index
      });
    },
    random(){
      this.randomPlay({
        list: this.songs
      });
    },
    ...mapActions([
      'selectPlay',
      'randomPlay'
    ])
  },
  mounted(){
    this.$refs.bgLayer.style.top = this.$refs.bgImg.clientHeight + 'px';
    this.initTop = parseInt(this.$refs.bgLayer.style.top);
  },
  computed:{
    bgStyle(){
      return `background-image:url(${this.bgImg})`;
    }
  },
  watch:{
    flag(){
      this.vm._setHeight();
      this.scroll.refresh();
    }
  },
  components:{
    SongsList
  }
}
</script>

<style scoped>
  .music-list{
    position: fixed;
    left: 0;
    top: 0;
    z-index: 100;
    width: 100%;
    height: 100%;
    background: #222;
    color: #ffffff;
  }
  .music-list .head{
    position: absolute;
    left: 0;
    top: 0;
    width: 100%;
    z-index:20;
  }
  .music-list .head .back{
    position: absolute;
    height: 40px;
    left: 10px;
  }
  .music-list .head .back .iconfont{
    line-height: 40px;
    color: #ff6600;
    font-size: 23px;
  }
  .music-list .head .title{
    width: 100%;
    height:40px;
    line-height: 40px;
    text-align: center;
    font-size: 18px;
  }
  .music-list .bg-img{
    position: relative;
    width: 100%;
    height: 0;
    padding-top: 70%;
    z-index: 10;
    background: left top/cover no-repeat;
    transform-origin: center top;
  }
  .music-list .bg-img .filter{
    position: absolute;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    background-color:rgba(7,17,27,.4);
  }
  .music-list .bg-img .filter .play-wrapper{
    box-sizing: border-box;
    position: absolute;
    bottom: 20px;
    left: 50%;
    width: 135px;
    border:1px solid #ffcd32;
    border-radius:100px;
    margin-left: -68px;
    padding: 7px 0;
    color:#ffcd32;
    text-align: center;
  }
  .music-list .bg-img .filter .play-wrapper span,.music-list .bg-img .filter .play-wrapper .iconfont{
    font-size:12px;
    vertical-align: center;
  }
  .music-list .bg-layer{
    position: absolute;
    width: 100%;
    height: 100%;
    left: 0;
    top: 0;
    background: #222;
  }
</style>



