<template>
  <div class="wrapper">
    <img src="./loading.gif" alt="" width="40" hright="40">
    <h2 class="title">{{title}}</h2>
  </div>
</template>

<script>
export default {
  name: "loading",
  props: {
    title: {
      type: String,
      default: '正在载入...'
    }
  }
}
</script>

<style scoped>
  .wrapper{
    width: 100%;
    text-align: center;
    font-size: 14px;
    color: #fff;
    transform: translateY(50%);
  }
  .wrapper img{
    margin-bottom: 20px;
  }
</style>



