<template>
 <div class="player" v-show="playList.length > 0">
  <div class="normal-player" v-show="fullScreen">
    <div class="background">
      <img :src="currentSong.songimage" alt="">
    </div>
    <div class="top">
      <div class="min-back" @click="back">
        <i class="iconfont icon-houtui"></i>
      </div>
      <div class="title" v-html="currentSong.songname"></div>
      <div class="subtitle" v-html="currentSong.singername"></div>
    </div>
    <div class="middle" @touchstart.prevent="middleTouchStart"
                        @touchmove.prevent="middleTouchMove"
                        @touchend="middleTouchEnd">
      <div class="middle-l" ref="middleL">
        <div class="cd-wrapper">
          <img :src="currentSong.songimage" width="100%" height="100%" alt="">
        </div>
        <div class="playing-lyric" v-html="playingLyric"></div>
      </div>
      <div class="middle-r" ref="middleR">
        <scroll :data="currentLyricLines" :ifSetHeight="false" :height="middleHeight" ref="scroll">
          <div class="lyric-wrapper">
            <p v-for="(line,index) in currentLyricLines"
               ref="line"
               :class="{'current': index=== currentLyricNum}">{{line.txt}}</p>
          </div>
        </scroll>
      </div>
    </div>
    <div class="bottom">
      <div class="dot-wrapper flChild clearFix">
        <p :class="{'color': currentShow === 'cd'}"></p>
        <p :class="{'color': currentShow === 'lyric'}"></p>
      </div>
      <div class="progress-wrapper">
        <span class="time time-l">{{format(this.currentTime)}}</span>
        <div class="progress-bar-wrapper">
          <ProgressBar :percent="percent" @changePercent="changePercent"></ProgressBar>
        </div>
        <span class="time time-r">{{format(this.currentSong.duration)}}</span>
      </div>
      <div class="operators">
        <i :class="modeState" @click="changeMode"></i>
        <i class="iconfont icon-yuanxinghoutui" @click="prev"></i>
        <i :class="playIcon" @click="togglePlay"></i>
        <i class="iconfont icon-qianjin" @click="next"></i>
        <i class="iconfont icon-shoucang"></i>
      </div>
    </div>
  </div>
  <div class="min-player" v-show="!fullScreen" @click="open">
    <div class="player-l">
      <img :src="currentSong.songimage" width="40px" height="40px" alt="">
      <div class="desc">
        <p class="title" v-html="currentSong.songname"></p>
        <p class="subtitle" v-html="currentSong.singername"></p>
      </div>
    </div>
    <div class="player-r">
      <div class="player-button">
        <i :class="playIcon" @click.stop="togglePlay"></i>
      </div>
      <div class="player-list">
        <i class="iconfont icon-bofangqi_shouyegequliebiao_" style="font-size: 45px;"></i>
      </div>
    </div>
  </div>
  <div class="playlist">
    <audio ref="audio" :src="playUrl"
           @canplay="ready"
           @error="error"
           @timeupdate="updateTime"
           @ended="end"></audio>
  </div>
 </div>
</template>

<script>
import {mapGetters,mapMutations} from 'vuex'
import ProgressBar from '../../base/progress-bar/progress-bar'
import {playMode} from '../../assets/js/config'
import {upset,getCurrentIndex} from '../../assets/js/util'
import LyricParser from 'lyric-parser'
import Scroll from '../../base/scroll/scroll'
const PLAYING_LYRIC_WIDTH = 50;
export default {
  name: "player",
  data(){
    return {
      songReady: false,
      currentTime : 0,
      currentLyric: null,
      middleHeight: 0,
      currentLyricNum:0,
      currentShow: 'cd',
      playingLyric: ''
    }
  },
  created(){
    this.touch = {}
  },
  computed:{
    currentLyricLines(){
      return this.currentLyric ? this.currentLyric.lines:[];
    },
    playIcon(){
      return this.playing ? 'iconfont icon-zanting':'iconfont icon-bofang1';
    },
    ...mapGetters([
      'fullScreen',
      'playList',
      'currentSong',
      'playing',
      'currentIndex',
      'mode',
      'sequenceList'
    ]),
    playUrl(){
      if (this.currentSong.url){
        return this.currentSong.url.join('');
      }
    },
    percent(){
      return this.currentTime/this.currentSong.duration;
    },
    modeState(){
      if (this.mode == 0){
        return 'iconfont icon-yinleshunxubofang';
      }else if (this.mode == 1){
        return 'iconfont icon-danquxunhuan';
      }else if(this.mode == 2){
        return 'iconfont icon-suijibofang';
      }
    }
  },
  watch:{
    currentSong(newSong,oldSong){
      if (newSong.songid === oldSong.songid) {
        return;
      }
      if (this.currentLyric){
        this.currentLyric.stop();
        this.currentLyric = null;
      }
      this.$nextTick(() => {
        this.$refs.audio.play();
        this.lyric();
        this.middleHeight = this.$refs.middleL.clientHeight + PLAYING_LYRIC_WIDTH;
        this.$refs.middleR.style.height = this.middleHeight + 'px';
      })
    },
    playing(){
      this.$nextTick(() => {
        const audio = this.$refs.audio;
        this.playing ? audio.play() : audio.pause();
        this.currentLyricPlay();
      })
    }
  },
  methods:{
    middleTouchStart(e){
      let touch = e.changedTouches[0];
      this.touch.init = true;
      this.touch.startX = touch.pageX;
      this.touch.startY = touch.pageY;
    },
    middleTouchMove(e){
      if (this.touch.init){
        let touch = e.changedTouches[0];
        let detailsX = touch.pageX - this.touch.startX;
        let detailsY = touch.pageY - this.touch.startY;
        let left = this.currentShow === 'cd' ? 0 : -window.innerWidth;
        let width = Math.min(0,Math.max(-window.innerWidth,left + detailsX));
        this.touch.percentWidth = Math.abs(width / window.innerWidth);
        this.$refs.scroll.$el.style.transform = `translate3d(${width}px,0,0)`;
        this.$refs.scroll.$el.style.transition = '0s';
        this.$refs.middleL.style.transition = '0s';
        this.$refs.scroll.$el.style.opacity = this.touch.percentWidth;
        this.$refs.middleL.style.opacity = 1 - this.touch.percentWidth;
      }
    },
    middleTouchEnd(){
      this.touch.init = false;
      let percentWidth = this.touch.percentWidth;
      let offsetWidth;
      this.$refs.middleL.style.transition = '300ms';
      this.$refs.scroll.$el.style.transition = "300ms";
      if (this.currentShow === 'cd') {
        if (percentWidth > 0.2){
          offsetWidth = -window.innerWidth;
          this.currentShow = 'lyric';
          this.$refs.scroll.$el.style.opacity = 1;
          this.$refs.middleL.style.opacity = 0;
        }else {
          offsetWidth = 0;
          this.$refs.scroll.$el.style.opacity = 0;
          this.$refs.middleL.style.opacity = 1;
        }
      }else if (this.currentShow === 'lyric') {
        if (percentWidth < 0.8){
          offsetWidth = 0;
          this.currentShow = 'cd';
          this.$refs.scroll.$el.style.opacity = 0;
          this.$refs.middleL.style.opacity = 1;
        }else {
          offsetWidth = -window.innerWidth;
          this.$refs.scroll.$el.style.opacity = 1;
          this.$refs.middleL.style.opacity = 0;
        }
      }
      this.$refs.scroll.$el.style.transform = `translate3d(${offsetWidth}px,0,0)`;
    },
    currentLyricPlay(){
      if (this.currentLyric) {
        this.currentLyric.togglePlay();
        if (this.playing){
          this.scrollLyric(this.currentLyricNum);
        }
      }
    },
    lyric(){
      this.currentSong.getLyric().then((res) => {
        this.currentLyric = new LyricParser(res,this.handleLyric);
        if (this.currentLyric && this.playing){
          this.currentLyric.play();
        }
        console.log(this.currentLyric);
      }).catch((err) => {
        this.currentLyric = null;
        this.playingLyric = '';
        this.currentLyricNum = 0;
      })
    },
    handleLyric({lineNum,txt}){
      this.currentLyricNum = lineNum;
      this.playingLyric = txt;
      this.scrollLyric(this.currentLyricNum);
    },
    scrollLyric(lineNum){
      if (lineNum >= 0 && lineNum <=5){
        this.$refs.scroll.scroll.scrollTo(0,0,1000);
      }else{
        this.$refs.scroll.scroll.scrollToElement(this.$refs.line[lineNum-5],1000);
      }
    },
    changeMode(){
      let mode = (this.mode + 1) % 3;
      this.setMode(mode);
      let list = null;
      if (playMode.random === mode){
        list = upset(this.sequenceList);
      }else{
        list = this.sequenceList;
      }
      //cuurrentIndex发生变化
      let currentIndex = getCurrentIndex(list,this.currentSong);
      this.setCurrentIndex(currentIndex);
      this.setPlayList(list);
    },
    end(){
      if (playMode.loop === this.mode){
        this.$refs.audio.currentTime = 0;
        this.$refs.audio.play();
        this.currentLyric.seek(0);
      }else{
        this.next();
      }
    },
    back(){
      this.setFullScreen(false);
    },
    open(){
      this.setFullScreen(true);
    },
    togglePlay(){
      this.setPlaying(!this.playing);
    },
    prev(){
      if (this.currentLyric){
        this.currentLyric.stop();
        this.currentLyric = null;
      }
      if (!this.songReady){
        return;
      }
      let index = this.currentIndex - 1;
      if (index === -1){
        index = this.playList.length -1;
      }
      this.setCurrentIndex(index);
      if (!this.playing){
        this.togglePlay();
      }
      this.songReady = false;
    },
    next(){
      if (this.currentLyric){
        this.currentLyric.stop();
        this.currentLyric = null;
      }
      if (!this.songReady){
        return;
      }
      let index = this.currentIndex + 1;
      if (index === this.playList.length){
        index = 0;
      }
      this.setCurrentIndex(index);
      if (!this.playing){
        this.togglePlay();
      }
      this.songReady = false;
    },
    ready(){
      this.songReady = true;
    },
    error(){
      this.songReady = true;
    },
    updateTime(e){
      this.currentTime = e.target.currentTime;
    },
    changePercent(percent){
      this.$refs.audio.currentTime = percent * this.currentSong.duration;
      if (!this.playing){
        this.$refs.audio.play();
        this.setPlaying(true);
      }
      if (percent !== 1){
        this.$refs.audio.play();
      }
      if (this.currentLyric){
        this.currentLyric.seek(this.$refs.audio.currentTime * 1000);
      }
    },
    format(interval){
      interval = interval | 0;
      let minute = interval / 60 | 0;
      let second = this._pad(interval % 60 | 0);
      return `${minute}:${second}`;
    },
    _pad(num,n = 2){
      let len = num.toString().length;
      while (len < n){
        num = '0' + num;
        len ++;
      }
      return num;
    },
    ...mapMutations({
      setFullScreen:'SET_FULLSCREEN',
      setPlaying:'SET_PLAYING',
      setCurrentIndex:'SET_CURRENTINDEX',
      setMode:'SET_MODE',
      setPlayList: 'SET_PLAYLIST',
      setSequenceList: 'SET_SEQUENCELIST'
    }),
  },
  components:{
    ProgressBar,
    Scroll
  }
}
</script>

<style scoped>
  .player .normal-player{
    position: fixed;
    left:0;
    top:0;
    width: 100%;
    height: 100%;
    background: #222;
    z-index: 100;
    color: #ffffff;
  }
  .player .normal-player .background{
    position: absolute;
    width: 100%;
    height: 100%;
    -webkit-filter: blur(20px);
    filter:blur(20px);
    opacity: 0.6;
  }
  .player .normal-player .background img{
    width: 100%;
    height: 100%;
  }
  .player .normal-player .top{
    position: relative;
    margin-bottom: 25px;
  }
  .player .normal-player .top .min-back{
    position: absolute;
    left: 6px;
    top: 0;
    width: 40px;
    height:40px;
    text-align: center;
    line-height: 40px;
    transform:rotate(-90deg);
    color:#ffcd32;
  }
  .player .normal-player .top .min-back .iconfont{
    font-size: 24px;
    font-weight: bold;
  }
  .player .normal-player .top .title{
    font-size: 18px;
    line-height: 40px;
  }
  .player .normal-player .top .subtitle{
    font-size: 14px;
  }
  .player .normal-player .middle{
    position: relative;
    white-space:nowrap;
  }
  .player .normal-player .middle .middle-l{
    position: relative;
    display: inline-block;
    width: 100%;
    height: 0;
    padding-top: 80%;
    vertical-align: top;
    opacity: 1;
  }
  .player .normal-player .middle .middle-l .cd-wrapper{
    position: absolute;
    left: 0;
    top: 0;
    width: 80%;
    height: 100%;
    margin-left: 10%;
    border-radius:50%;
    box-sizing: border-box;
    border: 10px solid hsla(0,0%,100%,.1);
  }
  .player .normal-player .middle .middle-l .cd-wrapper img{
    border-radius: 50%;
  }
  .player .normal-player .middle .middle-l .playing-lyric{
    width: 80%;
    margin:30px auto 0;
    text-align: center;
    height: 20px;
    line-height: 20px;
    font-size: 14px;
    color: hsla(0,0%,100%,.5);
    overflow: hidden;
  }
  .player .normal-player .middle .middle-r{
    position: relative;
    display: inline-block;
    width: 100%;
    height: 100%;
    line-height: 32px;
    color: hsla(0,0%,100%,.5);
    font-size: 14px;
    text-align: center;
    vertical-align: top;
  }
  .player .normal-player .middle .middle-r .wrapper{
    opacity: 0;
    overflow: hidden;
  }
  .player .normal-player .middle .middle-r .current{
    color: #ffffff;
  }
  .player .normal-player .bottom{
    width: 100%;
    position: absolute;
    bottom: 60px;
    left: 0;
    overflow: hidden;
  }
  .player .normal-player .bottom .dot-wrapper{
    position: absolute;
    left: 50%;
    top: 0;
    margin:0 -20px;
  }
  .player .normal-player .bottom .dot-wrapper p{
    width:10px;
    height: 10px;
    border-radius:50%;
    background-color: #ccc;
    margin:0 5px;
  }
  .player .normal-player .bottom .dot-wrapper p.color{
    background: #ff6600;
  }
  .player .normal-player .bottom  .operators{
    width: 100%;
    display: flex;
    justify-content:space-around;
    align-items: center;
    color: #ffcd32;
    margin-top: 10px;
  }
  .player .normal-player .bottom  .operators .iconfont{
    font-size: 35px;
  }
  .player .normal-player .bottom .progress-wrapper{
    display: flex;
    font-size: 14px;
    width: 85%;
    margin: 20px auto 10px;
    align-items: center;
  }
  .player .normal-player .bottom .progress-wrapper .progress-bar-wrapper{
    flex: 1;
    margin: 0 10px;
  }
  .player .min-player{
    position: fixed;
    bottom: 0;
    left: 0;
    width: 100%;
    padding: 0 10px 0 20px;
    box-sizing: border-box;
    height: 60px;
    background-color: #333;
    z-index: 120;
    display:flex;
    justify-content: space-between;
    align-items: center;
    color: #ffffff;
    text-align: left;
  }
  .player .min-player .player-l{
    display: flex;
  }
  .player .min-player .player-l img{
    border-radius:50%;
  }
  .player .min-player .player-l .desc{
    margin-left: 10px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
  }
  .player .min-player .player-l .desc .title{
    width: 160px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    font-size: 14px;
  }
  .player .min-player .player-l .desc .subtitle{
    font-size: 12px;
    color: hsla(0,0%,100%,.3);
  }
  .player .min-player .player-r{
    display: flex;
    align-items: center;
  }
  .player .min-player .player-r .iconfont{
    font-size:35px;
    color: #ffcd32;
  }
  .player .min-player .player-r .player-button .iconfont{
    margin-right: 10px;
  }
</style>



