<template>
  <div class="singer-wrap">
    <listview :data="singerList" v-if="singerList.length"  @singerChildren="singerChildren"></listview>
    <loading v-show="!singerList.length"></loading>
    <router-view></router-view>
  </div>
</template>

<script>
import {getSinger} from "../../api/singer.js"
import listview from '../../base/listview/listview'
import loading from '../../base/loading/loading'
import {mapMutations} from 'vuex'
export default {
  name: 'singer',
  data(){
    return {
      singerList:[]
    }
  },
  created(){
    this._getSingerList();
  },
  methods:{
    _getSingerList(){
      this.singerList = getSinger();
    },
    singerChildren(singer){
      this.$router.push({
        path: '/singer/'+singer.singer_id
      });
      this.setSinger(singer);
    },
    ...mapMutations({
      setSinger : 'SET_SINGER'
    })
  },
  components:{
    listview,
    loading
  }
}
</script>

<style scoped>
.singer-wrap{
  overflow: hidden;
}
</style>



