import Vue from 'vue'
import Router from 'vue-router'

import Rank from '../components/rank/rank'
import Recommend from '../components/recommend/recommend'
import Search from '../components/search/search'
import Singer from '../components/singer/singer'
import SingerChildren from '../components/singer/singerChildren'

Vue.use(Router)
export default new Router({
  routes: [
    {
      path: '/rank',
      component: Rank
    },
    {
      path: '/recommend',
      component: Recommend
    },
    {
      path: '/search',
      component: Search
    },
    {
      path: '/singer',
      component: Singer,
      children:[
        {
          path: ':id',
          component: SingerChildren
        }
      ]
    },
    {
      path: '/',
      redirect: '/recommend'
    }
  ],
  linkActiveClass: 'active'
})



