<template>
  <div class="recommend">
    <scroll :data="data">
      <div style="overflow: hidden">
        <div v-if="data.length" class="recommend-slider">
          <slider>
            <li v-for="item in data" :key="item.id" class="slider-item">
              <a :href="item.linkUrl">
                <img :src="item.picUrl" alt="">
              </a>
            </li>
          </slider>
        </div>
        <div class="recommend-list">
          <h2>热门歌单推荐</h2>
          <ul class="play-list">
            <li v-for="item in recommendList" class="list">
              <div class="img">
                <img v-lazy="item.imgurl" alt="" width="100%">
              </div>
              <div class="content">
                <p class="title" v-html="item.creator.name"></p>
                <p class="desc" v-html="item.dissname"></p>
              </div>
            </li>
          </ul>
        </div>
      </div>
      <div class="loading-wrapper" v-show="!recommendList.length">
        <loading></loading>
      </div>
    </scroll>
  </div>
</template>

<script>
import scroll from '../../base/scroll/scroll'
import slider from '../../base/slider/slider'
import playList from '../../assets/jsonData/playList'
import loading from '../../base/loading/loading'
export default {
  name: 'recommend',
  data() {
    return {
      data: [],
      recommendList:[]
    }
  },
  components: {
    slider,
    scroll,
    loading
  },
  created() {
    this.$axios.get('/api/musichall/fcgi-bin/fcg_yqqhomepagerecommend.fcg', {
      params: {
        g_tk: 5381,
        uin: 0,
        format: 'json',
        inCharset: 'utf-8',
        outCharset: 'utf-8',
        notice: 0,
        platform: 'h5',
        needNewCode: 1,
        _: 1530716985556
      }
    }).then(
      (response) => {
        this.data = response.data.data.slider
      });
    setTimeout(()=>{
      this.recommendList = playList.list;
    },1000)
  }
}
</script>

<style scoped>
  .recommend{
    overflow: hidden;
  }
  .recommend .loading-wrapper{
    width: 100%;
  }
  .recommend .recommend-list{
    font-size:16px;
  }
  .recommend .recommend-list h2{
    color: sandybrown;
    margin:20px 0;
  }
  .recommend .recommend-list .play-list .list{
    display:flex;
    justify-content: flex-start;
    width:100%;
    margin-bottom:20px;
  }
  .recommend .recommend-list .play-list .list .img{
    width:80px;
    margin: 0 20px;
  }
  .recommend .recommend-list .play-list .list .content{
    display: flex;
    flex-wrap: wrap;
    align-content: space-around;
    width:200px;
    text-align:left;
  }
  .recommend .recommend-list .play-list .list .content .title{
    width:100%;
    color: #ffffff;
    font-size: 14px;
  }
  .recommend .recommend-list .play-list .list .content .desc{
    width: 100%;
    color: #fff234;
    font-size: 14px;
    overflow: hidden;
    text-overflow:ellipsis;
    white-space: nowrap;
  }
</style>



