<template>
  <div class="slider" ref="slider">
    <ul class="slider-group" ref="sliderGroup">
      <slot></slot>
    </ul>
    <div class="dots">
      <span class="dot" v-for="(item,index) in dots" :class="{active:index === currentPageIndex}"></span>
    </div>
  </div>
</template>

<script>
import BScroll from 'better-scroll'
export default {
  name: 'slider',
  data() {
    return {
      dots: [],
      currentPageIndex: 0
    }
  },
  props: {
    loop: {
      type: Boolean,
      default: true
    },
    autoPlay: {
      type: Boolean,
      default: true
    },
    interval: {
      type: Number,
      default: 4000
    }
  },
  mounted: function () {
    this.$nextTick(function () {
      this._setSliderGroupWidth()
      this._initDot()
      this._initSlider()
      if (this.autoPlay){
        this._play();
      }
    })
    window.onresize = (() =>{
      if (!this.slider){
        return;
      }
      this._setSliderGroupWidth(true);
      this.slider.refresh();
    });
  },
  methods: {
    _setSliderGroupWidth(isRize) {
      let sliderWidth = this.$refs.slider.clientWidth
      let sliderGroup = this.$refs.sliderGroup
      let sliderItem = Array.from(sliderGroup.children)
      let sliderItemNum = sliderItem.length
      let width = 0
      for (var key in sliderItem) {
        let child = sliderItem[key]
        child.style.width = sliderWidth + 'px'
      }
      width = sliderWidth * sliderItemNum
      if (this.loop && !isRize) {
        width += 2 * sliderWidth
      }
      sliderGroup.style.width = width + 'px'
    },
    _initDot() {
      this.dots = new Array(this.$refs.sliderGroup.children.length)
    },
    _initSlider() {
      this.slider = new BScroll(this.$refs.slider, {
        scrollX: true,
        scrollY: false,
        momentum: false,
        snap: {
          loop: this.loop,
          threshold: 0.5,
          speed: 400
        },
        bounce: false,
        stopPropagation: true,
        click: true
      })
      this.slider.on("scrollEnd",() => {
        this.currentPageIndex = this.slider.getCurrentPage().pageX;
        if (this.autoPlay){
          clearTimeout(this.timer);
          this._play()
        }
      })
      this.$refs.slider.addEventListener("touchstart",() => {
        clearTimeout(this.timer);
      },false)
    },
    _play(){
      this.timer = setTimeout(() => {
        console.log(1);
        this.slider.next(400);
      },this.interval)
    }
  },
  destroyed(){
    console.log(2);
    clearTimeout(this.timer);
  }
}
</script>

<style scoped>
  .slider{
    position: relative;
    width: 100%;
    text-align: left;
    overflow: hidden;
  }
  .slider .slider-group .slider-item{
    float: left;
    width: 100%;
  }
  .slider .slider-group .slider-item img{
    width: 100%;
  }
  .slider .dots{
    position: absolute;
    left:50%;
    bottom: 10px;
    margin-left: -50px;
  }
  .slider .dots .dot{
    float: left;
    width: 10px;
    height: 10px;
    background: #ccc;
    border-radius:50%;
    margin:0 5px;
  }
  .slider .dots .active{
    background-color: #f60;
  }
</style>



