export function upset(list) {
  const initArrLen = list.length;
  const randomArr = createRandom(list);
  const upsetArr = [];
  for (var i = 0;i<initArrLen;i++){
    upsetArr.push(list[randomArr[i]]);
  }
  return upsetArr;
}
export function getCurrentIndex(list,song) {
  let currentIndex = list.findIndex((item) => {
    return item.songid == song.songid;
  });
  return currentIndex;
}
function createRandom(list){
  const initArrLen = list.length;
  let randomArr = [];
  while(randomArr.length != initArrLen){
    let random = (Math.random() * initArrLen) | 0;
    while(randomArr.includes(random)){
      random = (Math.random() * initArrLen) | 0;
    }
    randomArr.push(random);
  }
  return randomArr;
}



