import jsonp from '../assets/js/jsonp.js'
import {makePy} from './pinying.js'

const options = {param: "callback"};
export function getSinger() {
  const url = "https://u.y.qq.com/cgi-bin/musicu.fcg";
  const data = {
    g_tk: 2017062645,
    loginUin: 1358302452,
    hostUin: 0,
    format: 'jsonp',
    inCharset: 'utf8',
    outCharset: 'utf-8',
    notice: 0,
    platform: 'yqq',
    needNewCode: 0,
    data: {
      "comm": {"ct": 24, "cv": 10000},
      "singerList": {
        "module": "Music.SingerListServer",
        "method": "get_singer_list",
        "param": {"area": -100, "sex": -100, "genre": -100, "index": -100, "sin": 0, "cur_page": 1}
      }
    }
  };
  var map = [];
  !function getData(){
    jsonp(url, data, options).then((res) => {
      var singerData = res.singerList.data.singerlist;
      var hotJSON = {};
      var hotArr = [];
      hotJSON.title = '热门';
      for (var i=0;i<10;i++){
        hotArr.push(singerData[i]);
      }
      hotJSON.item = hotArr;
      map.push(hotJSON);
      for (var i=65;i<91;i++){
        var letter = String.fromCharCode(i);
        var resJSON = {};
        var resArr = [];
        resJSON.title = letter;
        singerData.forEach(( item,index) => {
          var letterIndex = makePy(item.singer_name[0])[0];
          if (letterIndex == letter){
            resArr.push(item);
          }
        });
        resJSON.item = resArr;
        if (resJSON.item.length != 0){
          map.push(resJSON);
        }
      }
    }).catch((err) => {
      console.log(err);
    })
  }();
  return map;
}
export function getSingerChildren(singermid) {
  const url = 'https://c.y.qq.com/v8/fcg-bin/fcg_v8_singer_track_cp.fcg';
  const options = {param: "jsonpCallback"};
  const data ={
    g_tk:5381,
    loginUin:0,
    hostUin:0,
    format:'jsonp',
    inCharset:'utf8',
    outCharset:'utf-8',
    notice:0,
    platform:'yqq',
    needNewCode:0,
    singermid:singermid,
    order:'listen',
    begin:0,
    num:100,
    songstatus:1
  };
  let map = [];
  jsonp(url, data, options).then((res) => {
    if (!res.code) {
      res.data.list.forEach((item) => {
        map.push(item);
      })
    }
  }).catch((err) => {
    console.log(err);
  })
  return map;
}
export function getSongURL(songmid){
  const url = 'https://c.y.qq.com/base/fcgi-bin/fcg_music_express_mobile3.fcg';
  const data = {
    g_tk:5381,
    loginUin:0,
    hostUin:0,
    format:'json',
    inCharset:'utf8',
    outCharset:'utf-8',
    notice:0,
    platform:'yqq',
    needNewCode:0,
    cid:205361747,
    uin:0,
    songmid:songmid,
    filename:`C400${songmid}.m4a`,
    guid:6816590118
  };
  const options = {param: "callback"};
  let songUrl = [];
  jsonp(url,data,options).then((res) => {
    if (!res.code){
      let urlData = res.data.items[0];
      let url = '';
      if (typeof urlData === 'object'){
        url = `http://dl.stream.qqmusic.qq.com/${urlData.filename}?vkey=${urlData.vkey}&guid=6816590118&uin=0&fromtag=66`
      }
      songUrl.push(url);
    }
  }).catch((err) => {
    console.log(err)
  })
  return songUrl;
}



