<template>
  <div class="wrapper">
    <MusicList :songs="songs" :title="title" :bg-img="bgImg"></MusicList>
  </div>
</template>

<script>
import {mapGetters} from 'vuex'
import {getSingerChildren} from '../../api/singer'
import {createSongs} from '../../assets/js/song'
import MusicList from '../music-list/music-list'
export default {
  name: "singerChildren",
  data(){
    return{
      songs : [],
      musicList : []
    }
  },
  computed: {
    ...mapGetters([
      'singer'
    ]),
    title(){
      return this.singer.singer_name;
    },
    bgImg(){
      return this.singer.singer_pic;
    }
  },
  created(){
    this._getSingerChildren(this.singer.singer_mid);
  },
  methods:{
    _getSingerChildren(singer_mid){
      if (!this.singer.singer_mid){
        this.$router.push('/singer');
        return;
      }
      this.musicList = getSingerChildren(singer_mid);
    },
    createSongs(musicList){
      if (!musicList){
        return;
      }
      musicList.forEach((item) => {
        let {musicData} = item;
        let songsData = createSongs(musicData);
        this.songs.push(songsData);
      })
    }
  },
  watch:{
    musicList:{
      handler: function () {
        this.createSongs(this.musicList);
      },
      deep:true
    }
  },
  components:{
    MusicList
  }
}
</script>

<style scoped>

</style>



