import {getSongURL} from '../../api/singer'
import {getLyric} from '../../api/song'
import {Base64} from 'js-base64'
class Song {
  constructor({songid,songmid,singername,songname,albumname,duration,songimage,url}){
    this.songid = songid;
    this.songmid = songmid;
    this.singername = singername;
    this.songname = songname;
    this.albumname = albumname;
    this.duration = duration;
    this.songimage = songimage;
    this.url  = url;
  }
  getLyric(){
    return new Promise((resolve,reject) => {
      getLyric(this.songmid).then((res) => {
        if (res.retcode === 0){
          this.lyric = Base64.decode(res.lyric);
          resolve(this.lyric)
        }else{
          reject("no lyric")
        }
      })
    })
  }
}
export function createSongs(musicData) {
  return new Song({
    songid: musicData.songid,
    songmid: musicData.songmid,
    singername:getSingerName(musicData.singer),
    songname: musicData.songname,
    albumname: musicData.albumname,
    duration: musicData.interval,
    songimage:`https://y.gtimg.cn/music/photo_new/T002R300x300M000${musicData.albummid
      }.jpg?max_age=2592000`,
    url: getURL(musicData.songmid)
  })
}
function getSingerName(singer) {
  let res = [];
  if (!singer) {
    res = '';
  }
  singer.forEach((item) => {
    res.push(item.name);
  })
  return res.join('/');
}
function getURL(songmid){
  let songUrl = getSongURL(songmid);
  return songUrl;
}



