<template>
  <scroll :data="songs" :probe-type="probeType" :listener-scroll="listenerScroll" @scroll="scroll">
    <ul class="songs-list">
      <li v-for="(item,index) in songs" @click="selectItem(item,index)">
        <div class="title">{{item.songname}}</div>
        <div class="desc">{{songsDesc(item)}}</div>
      </li>
    </ul>
    <loading v-show="!songs.length"></loading>
  </scroll>
</template>

<script>
import Scroll from '../scroll/scroll'
import Loading from '../loading/loading'
export default {
  name: "songslist",
  data(){
    return{
      scrollY: 0
    }
  },
  props:{
    songs:{
      type: Array,
      default:[]
    }
  },
  created(){
    this.listenerScroll = true;
    this.probeType = 3;
  },
  methods:{
    songsDesc(item){
      return `${item.singername}-${item.albumname}`
    },
    scroll(pos,vm,scroll){
      this.scrollY = pos.y;
      this.$emit("scrollobj",vm,scroll)
    },
    selectItem(item,index){
      this.$emit("select",item,index)
    }
  },
  watch:{
    scrollY(newY){
      this.$emit('scrollY',newY);
    }
  },
  components:{
    Scroll,
    Loading
  }
}
</script>

<style scoped>
.songs-list{
  padding: 10px 20px;
  text-align:left;
  line-height: 20px;
  font-size: 14px;
  overflow: hidden;
}
.songs-list li{
  padding:10px 0;
}
.songs-list li div:nth-child(1){
  margin-bottom: 5px;
}
.songs-list li .desc{
  width: 100%;
  text-overflow: ellipsis;
  overflow: hidden;
  white-space: nowrap;
  color: hsla(0,0%,100%,.3);
}
</style>



